  return <View pointerEvents={open ? 'auto' : 'none'} style={StyleSheet.absoluteFill}><Animated.View style={[styles.backdrop, backdropStyle]} /><GestureDetector gesture={pan}><Animated.View style={[styles.sheet, sheetStyle]} accessibilityViewIsModal accessibilityLabel="Sheet that bypasses scroll lock for inner ScrollView"><View style={styles.handle} /><Text style={styles.title}>Sheet that bypasses scroll lock for inner ScrollView</Text>{children}<Pressable onPress={onClose} accessibilityRole="button" style={styles.close}><Text>Close</Text></Pressable></Animated.View></GestureDetector></View>;
