import React, {useMemo, useState} from 'react';
import {KeyboardAvoidingView, Platform, Pressable, StyleSheet, Text, TextInput, View} from 'react-native';
type Field = {name: string; label: string; required?: boolean; keyboardType?: 'default' | 'email-address' | 'number-pad'};
export function FormWithAutoSaveIndicator({fields, onSubmit}: {fields: Field[]; onSubmit: (values: Record<string,string>) => Promise<void> | void}) {
  const [values, setValues] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const errors = useMemo(() => Object.fromEntries(fields.map(f => [f.name, f.required && !values[f.name]?.trim() ? `${f.label} is required` : null])), [fields, values]);
  const invalid = Object.values(errors).some(Boolean);
  return <KeyboardAvoidingView behavior={Platform.OS === 'ios' ? 'padding' : undefined} style={styles.wrap}>{fields.map((field) => <View key={field.name} style={styles.field}><Text style={styles.label}>{field.label}</Text><TextInput value={values[field.name] ?? ''} onChangeText={(text) => setValues(v => ({...v, [field.name]: text}))} onBlur={() => setTouched(t => ({...t, [field.name]: true}))} keyboardType={field.keyboardType ?? 'default'} accessibilityLabel={field.label} accessibilityHint={errors[field.name] || undefined} style={[styles.input, touched[field.name] && errors[field.name] && styles.inputError]} />{touched[field.name] && errors[field.name] ? <Text accessibilityLiveRegion="polite" style={styles.error}>{errors[field.name]}</Text> : null}</View>)}<Pressable disabled={invalid} onPress={() => onSubmit(values)} accessibilityRole="button" style={[styles.submit, invalid && styles.disabled]}><Text style={styles.submitText}>Save</Text></Pressable></KeyboardAvoidingView>;
}
const styles = StyleSheet.create({wrap: {gap: 14}, field: {gap: 6}, label: {fontWeight: '700', color: '#111827'}, input: {minHeight: 48, borderWidth: 1, borderColor: '#94a3b8', borderRadius: 12, paddingHorizontal: 12}, inputError: {borderColor: '#dc2626'}, error: {color: '#dc2626'}, submit: {minHeight: 48, borderRadius: 12, alignItems: 'center', justifyContent: 'center', backgroundColor: '#111827'}, disabled: {opacity: 0.45}, submitText: {color: 'white', fontWeight: '700'}});

// rn-385: reduced-motion-safe animation for Vote button with animated count change
import React from 'react';
import {Pressable, Text, View} from 'react-native';
import Animated, {useAnimatedStyle, useReducedMotion, useSharedValue, withSpring, withTiming} from 'react-native-reanimated';
export function VoteButtonWithAnimatedCountChangeInteraction({onActivate}) {
  const reduceMotion = useReducedMotion();
  const progress = useSharedValue(0);
  const style = useAnimatedStyle(() => ({transform: [{scale: 1 + progress.value * 0.04}], opacity: 0.92 + progress.value * 0.08}));
  const activate = () => { progress.value = reduceMotion ? 1 : withSpring(1, {damping:18, stiffness:220}); onActivate?.(); };
  return <View><Animated.View style={style}><Pressable accessibilityRole="button" accessibilityLabel="Vote button with animated count change" accessibilityHint="Activates without requiring motion or gestures" accessibilityActions={[{name:'activate',label:'Activate'}]} onAccessibilityAction={activate} hitSlop={{top:8,right:8,bottom:8,left:8}} style={{minHeight:44,minWidth:44}} onPressIn={() => { progress.value = withTiming(1, {duration: reduceMotion ? 0 : 120}); }} onPressOut={() => { progress.value = withTiming(0, {duration: reduceMotion ? 0 : 160}); }} onPress={activate}><Text>Vote button with animated count change</Text></Pressable></Animated.View></View>;
}

